# E2-Skeptic three-route assess for S45-T1-A-E2
def assess(record: dict) -> str:
    required = {'cache_authoritative', 'cache_ttl_s', 'transactions', 'blob_store', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (record["cache_authoritative"] or record["transactions"] == "cache")
    except Exception:
        return 'REDESIGN_PERSISTENCE'
    return 'PASS' if ok else 'REDESIGN_PERSISTENCE'

record = {"case_id": "CASO-IQU-045-1A", **{"blob_store":"object","transactions":"relational","cache_authoritative":False,"cache_ttl_s":300}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'cache_ttl_s'}
print(assess(valid), assess(invalid), assess(incomplete))

